-- STEG 3: import av saknade inskrifter ur rundata.sql (landskap Vg, 322 rader).
-- 322 kandidatrader. id = rundatas objectid (UUID) => spegeltabeller matchar.
-- Dedup: WHERE NOT EXISTS på signum + ON CONFLICT(id). Ren data, idempotent. Kör i editorn.
insert into public.runic_inscriptions
  (id, signum, alternative_signum, coordinates, coord_source, coord_confidence,
   transliteration, normalization, translation_sv, translation_en, dating_text,
   scholarly_notes, object_type, material, landscape, country, data_source)
select
  v.id::uuid, v.signum,
  case when v.alt is not null then string_to_array(v.alt,'|') else null::text[] end,
  case when v.lat is not null then point(v.lng::float8, v.lat::float8) else null::point end,
  case when v.lat is not null then 'rundata_evighetsrunor' else null end,
  case when v.lat is not null then 'high' else null end,
  v.translit, v.norm, v.tsv, v.ten, v.dating, v.notes, v.otype, v.material, v.landscape,
  coalesce(v.country,'Sweden'), 'rundata_evighetsrunor'
from (values
('c2d9d66a-984f-41de-bf53-b0b193a9a497','Vg 210','L 1985',58.3811,13.1461,'⁓ þa : iak : uar : gør : þa : uar : þushundraþ : tu : hu^ndraþ : tiuhu : uintr : ok : atta : fra : bʀrþ : gus :+ a+g+l+a+ ⁓ ¶ ⁓ aue ⁓ maria ⁓ gracia ⁓ plena ⁓ ¶ ⁓ dionisius : siþ ⁓ benediktus ⁓','Þá ek var gǫr, þá var þúshundrað tvau hundrað tjogu vetr ok átta frá byrð "Guðs. Agla. Ave "Maria gratia plena. "Dionysius sit benedictus.','Då jag var gjord, då var (det) ettusentvåhundratjugu vintrar och åtta från Guds börd. AGLA. Ave Maria gratia plena / Var hälsad Maria, full av nåd. Dionysius sit benedictus / Dionysius vare välsignad.','When I was completed, then there were thousand two hundred twenty winters and eight from the birth of God. Agla (''agla''= Thou art strong in eternity, Lord). Ave Maria gratia plena. Dionysius sit benedictus.','1228',NULL,'Kyrkklocka','Malm','Västergötland','Sweden'),
('b33da451-500b-47b4-81da-40988ee7a1bb','Vg 279',NULL,58.0331,12.1529,'§A mun : þu · mik : man : þik : un : þu : m(e)r : an : þʀr §B brmʀ mk','§A Mun þu mik, man þik! Unn þu meʀ, ann þeʀ! §B Barmi(?) mik(?)!','§A Tänk du på mig, jag tänker på dig. Älska du mig, jag älskar dig. §B Må du(?) förbarma (dig) över mig(?).','§A Think of me, I think of you! Love me, I love you! §B Have mercy(?) on me(?)!','1100-talet','Fyndnr GI 714a.','Vävkniv','Trä','Västergötland','Sweden'),
